import{_ as t,o as a,c as d,a3 as o}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Calendar — Developer Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Calendar — Developer Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/calendar"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Calendar — Developer Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/calendar"}]]},"headers":[],"relativePath":"developer-guide/calendar.md","filePath":"developer-guide/calendar.md","lastUpdated":1784746021000}'),r={name:"developer-guide/calendar.md"};function c(i,e,n,l,s,p){return a(),d("div",null,[...e[0]||(e[0]=[o('<h1 id="calendar-—-developer-guide" tabindex="-1">Calendar — Developer Guide <a class="header-anchor" href="#calendar-—-developer-guide" aria-label="Permalink to &quot;Calendar — Developer Guide&quot;">​</a></h1><blockquote><p><strong>Status: Implemented (v1)</strong><br> Meetings depends on Calendar (required) and projects via <code>upsertFromSource</code>. No calendar assignment in v1.</p></blockquote><h2 id="ownership" tabindex="-1">Ownership <a class="header-anchor" href="#ownership" aria-label="Permalink to &quot;Ownership&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concept</th><th>Owner</th></tr></thead><tbody><tr><td><code>calendar_events</code> table / CRUD / Week·Day·Month·Agenda UI</td><td>Calendar module</td></tr><tr><td>Meeting booking, host assignment, Zoom/Meet, reminders</td><td><a href="/developer-guide/meetings">Meetings</a> module (calls <code>CalendarEventService</code>)</td></tr></tbody></table><h2 id="model" tabindex="-1">Model <a class="header-anchor" href="#model" aria-label="Permalink to &quot;Model&quot;">​</a></h2><p><code>App\\Models\\CalendarEvent</code> — <code>BelongsToTenant</code>, <code>LogsActivity</code>, <code>SoftDeletes</code>.</p><p>Key fields: <code>organizer_id</code>, <code>starts_at</code>, <code>ends_at</code>, <code>all_day</code>, <code>timezone</code>, <code>status</code> (<code>scheduled</code>|<code>cancelled</code>), <code>source</code> (<code>manual</code>|<code>meeting</code>), nullable <code>source_type</code>/<code>source_id</code> (Meetings uses morph alias <code>meeting</code>).</p><p><strong>Excluded:</strong> <code>assignee_id</code>, calendar ACL, participants.</p><h2 id="visibility" tabindex="-1">Visibility <a class="header-anchor" href="#visibility" aria-label="Permalink to &quot;Visibility&quot;">​</a></h2><ul><li>Without <code>calendar.view_all</code>: <code>organizer_id = actor</code></li><li>With <code>calendar.view_all</code> or Owner superadmin: all tenant events</li><li><code>POST</code> always sets <code>organizer_id</code> to the authenticated user; <code>organizer_id</code> / <code>assignee_id</code> are <strong>prohibited</strong> on requests</li></ul><h2 id="service-contract-meetings-ready" tabindex="-1">Service contract (Meetings-ready) <a class="header-anchor" href="#service-contract-meetings-ready" aria-label="Permalink to &quot;Service contract (Meetings-ready)&quot;">​</a></h2><p><code>App\\Services\\Tenant\\CalendarEventService</code>:</p><ul><li><code>createForOrganizer</code>, <code>update</code>, <code>cancel</code>, <code>delete</code></li><li><code>listInRange</code>, <code>upcoming</code></li><li><code>upsertFromSource</code> — used by Meetings; unused by Calendar UI in v1</li></ul><h2 id="frontend" tabindex="-1">Frontend <a class="header-anchor" href="#frontend" aria-label="Permalink to &quot;Frontend&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Piece</th><th>Location</th></tr></thead><tbody><tr><td>Page</td><td><code>src/pages/calendar/calendar-page.tsx</code></td></tr><tr><td>Time grid (Week/Day + DnD)</td><td><code>src/pages/calendar/calendar-time-grid.tsx</code> (<code>@dnd-kit/core</code>)</td></tr><tr><td>Form / detail</td><td><code>calendar-event-form-dialog.tsx</code>, <code>calendar-event-detail-sheet.tsx</code></td></tr><tr><td>Datetime helpers</td><td><code>src/lib/datetime.ts</code> (<code>appTimezone</code>, <code>moveEventToSlot</code>, …)</td></tr><tr><td>API</td><td><code>calendarService</code> in <code>src/api/services.ts</code></td></tr><tr><td>E2E</td><td><code>e2e/tests/calendar/</code>, <code>npm run test:e2e:calendar</code></td></tr></tbody></table><p>Drag-and-drop on Week/Day calls <code>PUT /calendar/events/{id}</code> with new <code>starts_at</code> / <code>ends_at</code> (15-minute snap). Display and inputs use the workspace timezone from settings.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>Configured in <code>config/tenant-permissions.php</code> + default role map:</p><table tabindex="0"><thead><tr><th>Role</th><th>Grants</th></tr></thead><tbody><tr><td>admin</td><td>all including <code>view_all</code></td></tr><tr><td>manager</td><td>all except <code>delete</code>; includes <code>view_all</code></td></tr><tr><td>staff</td><td><code>view</code>, <code>create</code>, <code>update</code>, <code>delete</code> (own only via policy); no <code>view_all</code></td></tr></tbody></table><h2 id="registration" tabindex="-1">Registration <a class="header-anchor" href="#registration" aria-label="Permalink to &quot;Registration&quot;">​</a></h2><p>Migrate-only:</p><ul><li><code>2026_07_20_230514_create_calendar_events_table.php</code></li><li><code>2026_07_21_040000_register_calendar_module.php</code></li><li><code>2026_07_21_040001_add_calendar_permissions.php</code></li></ul><p>Also listed in <code>CatalogSeeder</code> for fresh/local/CI.</p><h2 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h2><p><code>DashboardWidgetService</code> registers widget id <code>calendar</code> (upcoming events), gated by <code>module:calendar</code> + <code>calendar.view</code>, scoped by <code>calendar.view_all</code>.</p><h2 id="audit-activity" tabindex="-1">Audit &amp; activity <a class="header-anchor" href="#audit-activity" aria-label="Permalink to &quot;Audit &amp; activity&quot;">​</a></h2><ul><li>Spatie <code>LogsActivity</code> on <code>CalendarEvent</code> records attribute changes.</li><li><code>App\\Listeners\\CalendarEventSubscriber</code> (registered in <code>AppServiceProvider</code>) writes platform audit entries (<code>activity</code> log name <code>platform</code>) for <code>calendar_event_created|updated|cancelled|deleted</code>, mirroring Leads/Tasks/Communication Templates.</li></ul><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><ul><li>Pest: <code>tests/Feature/Tenant/Calendar/CalendarEventTest.php</code></li><li>Playwright: <code>npm run test:e2e:calendar</code></li></ul><h2 id="explicit-non-goals-v1" tabindex="-1">Explicit non-goals (v1) <a class="header-anchor" href="#explicit-non-goals-v1" aria-label="Permalink to &quot;Explicit non-goals (v1)&quot;">​</a></h2><p>Assignment, team calendars, invitee Calendar ACL, Google/Outlook sync, Task/Lead overlays. Meetings/Zoom/Meet live in the Meetings module.</p>',31)])])}const m=t(r,[["render",c]]);export{u as __pageData,m as default};
